class Solution:
    def winningPlayerCount(self, n: int, pick: list) -> int:
        from collections import defaultdict
        wins = 0
        for player in range(n):
            color_count = defaultdict(int)
            for x, y in pick:
                if x == player:
                    color_count[y] += 1
            if color_count and max(color_count.values()) > player:
                wins += 1
        return wins

