class Solution:
    def winningPlayerCount(self, n: int, pick: list) -> int:
        from collections import defaultdict
        player_colors = defaultdict(lambda: defaultdict(int))
        for x, y in pick:
            player_colors[x][y] += 1
        wins = 0
        for player in range(n):
            if player_colors[player] and max(player_colors[player].values()) > player:
                wins += 1
        return wins

solutions.javascript:
var winningPlayerCount = function(n, pick) {
    const playerColors = Array.from({length: n}, () => new Map());
    for (const [x, y] of pick) {
        playerColors[x].set(y, (playerColors[x].get(y) || 0) + 1);
    }
    let wins = 0;
    for (let i = 0; i < n; i++) {
        const maxCount = playerColors[i].size === 0 ? 0 : Math.max(...playerColors[i].values());
        if (maxCount > i) wins++;
    }
    return wins;
};
